#include <stdio.h>

int main()
{
    char n,i;
    long l,r,x,j;
    long min,max,sum,count=0;
    char s;
    scanf("%d%ld%ld%ld",&n,&l,&r,&x);
    long c[n];
    for(i=0;i<n;i++)
        scanf("%ld",c+i);
    long a=1L<<n;
    for(j=1;j<a;j++){
        min=1000000;
        max=1;
        sum=0;
        s=0;
        for(i=0;i<n;i++)
            if(j&(1L<<i)){
                if(c[i]<min)min=c[i];
                if(c[i]>max)max=c[i];
                sum+=c[i];
                s++;
            }
        if(s>1 && sum>=l && sum<=r && (max-min)>=x)
            count++;
    }
    printf("%ld\n",count);
    return 0;
}

