fn read_line(mut buffer: &mut String) -> Vec<usize> {
    std::io::stdin().read_line(&mut buffer).expect("Error while reading input.");
    let data = buffer.split_whitespace().map(|x| x.parse::<usize>().unwrap()).collect();
    buffer.clear();
    data
}

fn get_index(i: usize, n: usize) -> String {
    let bin_str = format!("{:0width$b}", i, width = n);
    bin_str
}

fn limit(n: usize) -> usize {
    let mut n_bin = String::with_capacity(n);
    for _i in 0..n {
        n_bin.push('1');
    }
    let limit = usize::from_str_radix(&n_bin, 2).unwrap();
    limit
}
fn calculate(index: &String, c: &Vec<usize>, min: usize, max: usize, diff: usize) -> usize {
    let mut sum = 0;
    let mut cmin = 10_usize.pow(6) + 1;
    let mut cmax = 0;
    for (i, ch) in index.chars().enumerate() {
       if ch == '1' {
            if c[i] > cmax {
                cmax = c[i];
            }
            if c[i] < cmin {
                cmin = c[i];
            }
            sum += c[i]; 
       }
    }
    // need to find min and max
    if sum >= min && sum <= max && (cmax - cmin) >= diff {
       return 1 
    }
    0
}

fn get_count(index: &String) -> usize {
    let mut count = 0;
    for ch in index.split("") {
        if ch == "1" {
            count += 1;
        }
    }
    count
}

fn main() {
    let mut buffer = String::new();

    let d = read_line(&mut buffer);
    //println!("D: {:?}", d);

    let (n, min, max, diff) = (d[0], d[1], d[2], d[3]);

    let c = read_line(&mut buffer);
    //println!("c: {:?}", c);

    let limit = limit(n);
    let mut result = 0;

    for i in 1..=limit {
        let index = get_index(i, n);
        let count = get_count(&index);
        if count > 1 { 
            //println!("{:?}", index);
            let res = calculate(&index, &c, min, max, diff);
            if res == 1 {
                //println!("now");
            }
            result += res;
        }
    }
    println!("{}", result);
}
